alter table public.profiles enable row level security;

do $$
begin
  if not exists (
    select 1
    from pg_policies
    where schemaname = 'public'
      and tablename = 'profiles'
      and policyname = 'profiles_select_own_rows'
  ) then
    create policy profiles_select_own_rows
      on public.profiles
      for select
      to authenticated
      using (auth.uid() = id);
  end if;
end $$;

alter table public.profiles enable row level security;

create policy "Users can select their own profile"
on public.profiles
for select
to authenticated
using (auth.uid() = id);
